-- 改动 2: frontend/src/App.tsx extractPayloadText() 增强 --

不修改 extractPayloadText() (它负责文本提取, 职责不变)。
在 handleSendMessage 和 handleWSMessage 中, 除了调用 extractPayloadText(),
追加提取教学字段的逻辑:

// 在 handleSendMessage 的 addMessage 调用之前:
const coachMsg: ChatMessage = {
  id: nextMsgId(),
  role: 'coach',
  content: extractPayloadText(res.payload, res.action_type),
  actionType: res.action_type as ChatMessage['actionType'],
  sourceTag: ...,
  timestamp: new Date().toISOString(),
  pulse: res.pulse ?? undefined,
  // Phase 19-26: 教学元数据
  llm_generated: res.llm_generated ?? undefined,
  difficulty_contract: res.difficulty_contract ?? undefined,
  personalization_evidence: res.personalization_evidence ?? undefined,
  memory_status: res.memory_status ?? undefined,
  awakening: res.awakening ?? undefined,
};
addMessage(coachMsg);

